// ─── DIFFICULTY HELPER ────────────────────────────────────────────────────────
function getDifficulty(type, subj) {
  if (type === "positive") return subj.number === "singular" ? "easy" : "medium";
  if (type === "negative") return "medium";
  return "hard";
}

// ─── BUILD PRACTICE + MOCKTEST ────────────────────────────────────────────────
function buildSentences(totalNeeded, idPrefix, excludeSet) {
  const items = [];
  const englishSet = new Set(excludeSet || []);
  
  // Build all possible combinations
  const combos = [];
  for (const subj of subjects) {
    for (const vp of verbPhrases) {
      for (const type of ["positive", "negative", "question"]) {
        combos.push({ subj, vp, type });
      }
    }
  }
  
  // Generate sentences from combos
  let idx = 0;
  const seenCombos = [];
  
  for (const { subj, vp, type } of combos) {
    let english, hindi;
    const conj = subj.conjugation;
    
    if (type === "positive") {
      // Use toVerb form
      english = `${subj.eng} wanted ${vp.toVerb}.`;
      hindi = `${subj.hindi} ${vp.hindiToVerb} ${conj}.`;
    } else if (type === "negative") {
      english = `${subj.eng} did not want ${vp.toVerb}.`;
      hindi = `${subj.hindi} ${vp.hindiToVerb} नहीं ${conj}.`;
    } else {
      // Question — only for first-person or specific subjects
      english = `Did ${subj.eng.toLowerCase() === "i" ? "you" : subj.eng.toLowerCase()} want ${vp.toVerb}?`;
      hindi = `क्या ${subj.hindi} ${vp.hindiToVerb} ${conj}?`;
    }
    
    if (!englishSet.has(english)) {
      englishSet.add(english);
      seenCombos.push({ english, hindi, subj, vp, type });
    }
  }
  
  // Also generate noun-form sentences for more variety
  for (const subj of subjects) {
    for (const vp of verbPhrases) {
      for (const type of ["positive", "negative", "question"]) {
        let english, hindi;
        const conj = subj.conjugation;
        
        if (type === "positive") {
          english = `${subj.eng} wanted ${vp.noun}.`;
          hindi = `${subj.hindi} को ${vp.hindiNoun} चाहिए था / ${vp.hindiNoun} ${conj}.`;
        } else if (type === "negative") {
          english = `${subj.eng} did not want ${vp.noun}.`;
          hindi = `${subj.hindi} को ${vp.hindiNoun} नहीं चाहिए था.`;
        } else {
          english = `Did ${subj.eng.toLowerCase() === "i" ? "you" : subj.eng.toLowerCase()} want ${vp.noun}?`;
          hindi = `क्या ${subj.hindi} को ${vp.hindiNoun} चाहिए था?`;
        }
        
        if (!englishSet.has(english)) {
          englishSet.add(english);
          seenCombos.push({ english, hindi, subj, vp, type });
        }
      }
    }
  }
  
  // Shuffle and take what we need
  for (let i = seenCombos.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [seenCombos[i], seenCombos[j]] = [seenCombos[j], seenCombos[i]];
  }
  
  const selected = seenCombos.slice(0, totalNeeded);
  
  for (let i = 0; i < selected.length; i++) {
    const { english, hindi, subj, vp, type } = selected[i];
    const num = String(i + 1).padStart(3, '0');
    const diff = getDifficulty(type, subj);
    
    // Generate alternatives
    const alternatives = [];
    if (type === "positive") {
      if (english.includes(" wanted to ")) {
        alternatives.push(english.replace(" wanted to ", " had wanted to ").toLowerCase().replace(/\.$/, '.'));
      }
    } else if (type === "negative") {
      alternatives.push(english.replace("did not want", "didn't want").toLowerCase().replace(/^\w/, c => c.toLowerCase()));
    }
    
    // Hint and explanation
    let hint, explanation;
    if (type === "positive") {
      hint = "Subject + wanted + to + base verb";
      explanation = `'Wanted' is the simple past of 'want', used for all subjects. ${subj.eng} wanted (${subj.conjugation}).`;
    } else if (type === "negative") {
      hint = "Subject + did not want + to + base verb";
      explanation = `Negative: 'did not want' — never 'didn't wanted'. The base form 'want' follows 'did'.`;
    } else {
      hint = "Did + subject + want + to + base verb?";
      explanation = `Question form: 'Did' at the start, then subject, then base form 'want' (not 'wanted').`;
    }
    
    items.push({
      id: `${idPrefix}${num}`,
      hindi: hindi,
      english: english,
      alternatives: alternatives.filter(a => a !== english.toLowerCase()),
      hint,
      explanation,
      difficulty: diff,
      tags: [type, vp.topic, "wanted", "day12"]
    });
  }
  
  return { items, englishSet };
}

// Build practice (900)
